    tierOrder: ["s","a","b","c"],
    books: {"rf1":{"id":"rf1","title":"House of Flame and Shadow","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/court-fure.jpeg"},"rf2":{"id":"rf2","title":"House of Sky and Breath","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/court-rose.jpeg"},"rf3":{"id":"rf3","title":"House of Earth and Blood","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/court-ruin.jpeg"},"rf4":{"id":"rf4","title":"The Alchemised","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/alchemisen.jpeg"},"rf5":{"id":"rf5","title":"Iron Flame","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/iron-fire.jpeg"},"rf6":{"id":"rf6","title":"Rites of the Starling","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/rites-starling.jpeg"},"rf7":{"id":"rf7","title":"The Mate","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/mate.jpg"},"rf8":{"id":"rf8","title":"Onix","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/onix.jpeg"},"rf9":{"id":"rf9","title":"Sera","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/sera.jpg"},"rf10":{"id":"rf10","title":"Rtut","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/rtut.jpeg"},"rf11":{"id":"rf11","title":"Shield of Sparrows","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/shield-sparrows.jpeg"},"rf12":{"id":"rf12","title":"Wing","author":"","description":"","coverImageUrl":"/images/collections/curated/romantic-fantasy/wing.jpeg"},"curated_1_1782390604813":{"id":"curated_1_1782390604813","tags":["Тёмный роман"],"genre":"Ромэнтези","title":"Crown Me Dead","author":"Лив Зандер","rating":8.4,"description":"Стань моей женой. Раздели со мной ложе. Перережь себе горло.\n\nЯ родилась в грязи и выросла среди гнили. Я копаю могилы для мёртвых, пока живые вокруг медленно разлагаются заживо.\nКогда мой брат начинает кашлять кровью, появляется он.\nМужчина, слишком безупречный для кладбища, и с предложением слишком жестоким для света дня:\nСоблазни короля.\nСтань королевой.\nУмри.\nИ тогда мой брат будет жить.\nКаэль — воплощённый кошмар, король умирающего королевства, прогнившего до самого основания. А Вейл — его тень, холодный архитектор моей гибели.\nОдному нужно, чтобы моё сердце продолжало биться.\nДругой намерен остановить его навсегда.\nОни считают меня пешкой.\nНо я дочь могильщика.\nИ я прекрасно знаю, где хоронят таких, как они.\nДобро пожаловать на похороны.","coverImageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1775423929i/250681590.jpg"},"curated_2_1782388225728":{"id":"curated_2_1782388225728","tags":["драконы","феи","романтика"],"genre":"Романтическое фэнтези","title":"Баллада о падающих драконах","author":"Сара А. Паркер","rating":9,"description":"Жажда мести в сердце Рэв не угасает. Как не угасает и её любовь к Каану Ваэгору — последнему светлому маяку из прошлого, с которым ей ещё только предстоит столкнуться лицом к лицу. Кровь Рекка всё ещё не смыта с её рук, когда она узнаёт: миру предстоит пережить самый разрушительный Лунопад за всю историю. И теперь ей придётся сделать выбор:\n\nПойти по следу смерти.\n\nИли выбрать жизнь.\n\nКаан отчаянно пытается уберечь своё королевство от гибели, но корона ещё никогда не казалась ему такой тяжёлой ношей. Его многочисленные послания, разосланные друзьям и родным, разбросанным по миру, остаются без ответа, а времени остаётся всё меньше.","coverImageUrl":"https://m.media-amazon.com/images/S/compressed.photo.goodreads.com/books/1764279945i/216815055.jpg"}},
